/* on.standard.board.comboard.mergeBoardInfo */



        SELECT IFNULL(MAX(BOARD_SERNO), 0) + 1
        FROM STB_SM_BOARD_MNG
        WHERE BOARD_DIV_CD = #{menuFuncCd}


        SELECT #{boardSerno}



INSERT INTO STB_SM_BOARD_MNG (
                               BOARD_DIV_CD
                             , BOARD_SERNO , UPPER_BOARD_SERNO
                             , TITL
                             , CONTENT
                             , REG_USER
                             , REG_DATE
                             , USE_YN
                             , NTI_YN
                             , RCMD_YN
                             , RCMD_COUNT
                             , NTI_STRT_DT
                             , NTI_END_DT
                             , ATCH_FILE_ID
                             , OPEN_YN
                             , SCRET_YN
                             , BLTNB_PSWD
                             , TEMPCOL_1
                             , TEMPCOL_2
                             , TEMPCOL_3
                             , TEMPCOL_4
                             , TEMPCOL_5
                             , TEMPCOL_6
                             , TEMPCOL_7
                             , TEMPCOL_8
                             , TEMPCOL_9
                             , TEMPCOL_10
) VALUES (
           #{menuFuncCd}
         , #{boardSerno}      , #{upperBoardSerno}
         , #{titl}
         , #{content}
         , #{loginUserId}     , NOW()
         , IFNULL(#{useYn}, 'Y')
         , IFNULL(#{ntiYn}, 'N')
         , IFNULL(#{rcmdYn}, 'N')
         , IFNULL(#{rcmdCount}, 0)
         , #{ntiStrtDt}
         , #{ntiEndDt}
         , #{atchFileId}
         , #{openYn}
         , IFNULL(#{scretYn}, 'N')
         , #{boardPswd}
         , #{tempcol1}
         , #{tempcol2}
         , #{tempcol3}
         , #{tempcol4}
         , #{tempcol5}
         , #{tempcol6}
         , #{tempcol7}
         , #{tempcol8}
         , #{tempcol9}
         , #{tempcol10}
         )
    ON DUPLICATE KEY UPDATE
     UPPER_BOARD_SERNO   = #{upperBoardSerno}
     , TITL              = #{titl}
     , CONTENT           = #{content}
     , UPD_USER          = #{loginUserId}
     , UPD_DATE          = NOW()
     , USE_YN            = IFNULL(#{useYn}, USE_YN)
     , NTI_YN            = IFNULL(#{ntiYn}, NTI_YN)
     , RCMD_YN           = IFNULL(#{rcmdYn}, RCMD_YN)
     , RCMD_COUNT        = IFNULL(#{rcmdCount}, RCMD_COUNT)
     , NTI_STRT_DT       = #{ntiStrtDt}
     , NTI_END_DT        = #{ntiEndDt}
     , ATCH_FILE_ID      = #{atchFileId}
     , OPEN_YN           = #{openYn}
     , SCRET_YN          = IFNULL(#{scretYn}, SCRET_YN)
     , BLTNB_PSWD        = #{boardPswd}
     , TEMPCOL_1         = #{tempcol1}
     , TEMPCOL_2         = #{tempcol2}
     , TEMPCOL_3         = #{tempcol3}
     , TEMPCOL_4         = #{tempcol4}
     , TEMPCOL_5         = #{tempcol5}
     , TEMPCOL_6         = #{tempcol6}
     , TEMPCOL_7         = #{tempcol7}
     , TEMPCOL_8         = #{tempcol8}
     , TEMPCOL_9         = #{tempcol9}
     , TEMPCOL_10        = #{tempcol10}

mapper.update:
/* on.standard.board.comboard.deleteBoardInfo */
 UPDATE STB_SM_BOARD_MNG
   SET USE_YN = 'N'
     , UPD_DATE = NOW()
     , UPD_USER = #{loginUserId}
 WHERE BOARD_DIV_CD = #{menuFuncCd}
   AND BOARD_SERNO  = #{boardSerno}
